    description: "",
    manufacturingStory: "",
    manufacturingInfographic: "",
    mainImage: "",
    samplePrice: "",
    weight: "",
    material: "",
    availableSizes: JSON.stringify(["S", "M", "L", "XL", "2XL"]),
    availableColors: JSON.stringify(["Black", "White", "Navy"]),
    isFeatured: false,
    isActive: true,
    freeShipping: false,
    sortOrder: 0,
    seoTitle: "",
    seoDescription: "",
    seoKeywords: ""
