function buildStitchGuide(w, h, inset, labelStyle, accentColor = "rgba(150,130,100,0.5)") {
  const elements = [];
  if (labelStyle === "center-fold" || labelStyle === "loop-fold") {
    elements.push({
      type: "rect",
      id: "sg-top-gutter",
      left: 0,
      top: 0,
      width: w,
      height: inset,
      fill: "rgba(0,0,0,0.06)",
      selectable: false,
      evented: false,
      isStitchGuide: true
    });
  }
  elements.push({
    type: "rect",
    id: "sg-bottom-gutter",
    left: 0,
    top: h - inset,
    width: w,
    height: inset,
    fill: "rgba(0,0,0,0.06)",
    selectable: false,
    evented: false,
    isStitchGuide: true
  });
  elements.push({
    type: "rect",
    id: "sg-left-gutter",
    left: 0,
    top: inset,
    width: inset,
    height: h - inset * 2,
    fill: "rgba(0,0,0,0.06)",
    selectable: false,
    evented: false,
    isStitchGuide: true
  });
  elements.push({
    type: "rect",
    id: "sg-right-gutter",
    left: w - inset,
    top: inset,
    width: inset,
    height: h - inset * 2,
    fill: "rgba(0,0,0,0.06)",
    selectable: false,
    evented: false,
    isStitchGuide: true
  });
  elements.push(
    { type: "line", id: "sg-stitch-top", x1: inset, y1: inset, x2: w - inset, y2: inset, stroke: accentColor, strokeWidth: 1.2, strokeDashArray: [6, 5], selectable: false, evented: false, isStitchGuide: true },
    { type: "line", id: "sg-stitch-bottom", x1: inset, y1: h - inset, x2: w - inset, y2: h - inset, stroke: accentColor, strokeWidth: 1.2, strokeDashArray: [6, 5], selectable: false, evented: false, isStitchGuide: true },
    { type: "line", id: "sg-stitch-left", x1: inset, y1: inset, x2: inset, y2: h - inset, stroke: accentColor, strokeWidth: 1.2, strokeDashArray: [6, 5], selectable: false, evented: false, isStitchGuide: true },
    { type: "line", id: "sg-stitch-right", x1: w - inset, y1: inset, x2: w - inset, y2: h - inset, stroke: accentColor, strokeWidth: 1.2, strokeDashArray: [6, 5], selectable: false, evented: false, isStitchGuide: true }
  );
  if (labelStyle === "center-fold" || labelStyle === "loop-fold") {
    elements.push({
      type: "rect",
      id: "sg-fold-line",
      left: 0,
      top: h / 2,
      width: w,
      height: 1.5,
      fill: "rgba(0,0,0,0.12)",
      selectable: false,
      evented: false,
      isStitchGuide: true
    });
  }
  if (labelStyle === "end-fold" || labelStyle === "mitre-fold") {
    elements.push({
      type: "rect",
      id: "sg-left-flap",
      left: 0,
      top: 0,
      width: inset * 1.5,
      height: h,
      fill: "rgba(0,0,0,0.07)",
      selectable: false,
      evented: false,
      isStitchGuide: true
    }, {
      type: "rect",
      id: "sg-right-flap",
      left: w - inset * 1.5,
      top: 0,
      width: inset * 1.5,
      height: h,
      fill: "rgba(0,0,0,0.07)",
      selectable: false,
      evented: false,
      isStitchGuide: true
    });
  }
  return elements;
}
